mapper.select:
SELECT COUNT(*)
FROM openplatform_v2_cp_execution_record_t
WHERE flow_id = #{flowId}

mapper.delete:
DELETE FROM openplatform_v2_cp_execution_record_t
WHERE id IN (
    SELECT id FROM (
        SELECT id FROM openplatform_v2_cp_execution_record_t
        WHERE flow_id = #{flowId}
        ORDER BY create_time ASC
        LIMIT #{limit}
    ) AS tmp
)

DELETE FROM openplatform_v2_cp_execution_record_t
WHERE trigger_time  <  #{beforeTime}
LIMIT #{limit}
